import{_ as a,o as l,c as i,ai as t}from"./chunks/framework.ampVZV4B.js";const d=JSON.parse('{"title":"AI 探索（独立模块）","description":"","frontmatter":{},"headers":[],"relativePath":"ai/index.md","filePath":"ai/index.md"}'),r={name:"ai/index.md"};function s(o,e,n,m,h,p){return l(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="ai-探索-独立模块" tabindex="-1">AI 探索（独立模块） <a class="header-anchor" href="#ai-探索-独立模块" aria-label="Permalink to “AI 探索（独立模块）”">​</a></h1><blockquote><p>这里是专门给自己的 <strong>AI / 大模型学习、探索热门工具与开源项目</strong> 留的空间，不再和传统「Java / 数据库 / 框架」技术库混在一起，方便单独规划。<br><strong>命名说明</strong>：顶栏使用 <strong>「AI 探索」</strong>——模块内仍包含<strong>阶段路线与循序渐进</strong>（偏系统学习）与<strong>热门软件与开源生态地图</strong>（偏工具与选型），避免旧名「AI 开发」过于像岗位职责描述。</p></blockquote><hr><h2 id="🔥-热门-ai-软件与开源项目-探索入口" tabindex="-1">🔥 热门 AI 软件与开源项目（探索入口） <a class="header-anchor" href="#🔥-热门-ai-软件与开源项目-探索入口" aria-label="Permalink to “🔥 热门 AI 软件与开源项目（探索入口）”">​</a></h2><p>想先看「当下都在用什么、该 Star 谁」——从这里进入：</p><ul><li><a href="/my-vitepress-site/ai/explore/"><strong>AI 热门软件与开源项目地图</strong></a>：按 <strong>对话与编程辅助、本地推理、Agent 编排、RAG、推理服务、多模态</strong> 等维度整理，附学习优先级与站内文档跳转。</li></ul><hr><h2 id="🧭-从哪里开始看" tabindex="-1">🧭 从哪里开始看？ <a class="header-anchor" href="#🧭-从哪里开始看" aria-label="Permalink to “🧭 从哪里开始看？”">​</a></h2><p>如果你现在只是普通开发，希望<strong>先快速入门，再一步步深入</strong>，建议走这条路径：</p><ol><li><strong>先跑通 7 天快速入门</strong><ul><li><a href="/my-vitepress-site/ai/quickstart.html">AI 快速入门（7 天）</a></li></ul></li><li><strong>再看全局路线图（知道后面学什么）</strong><ul><li><a href="/my-vitepress-site/ai/ai-roadmap.html">AI 时代开发者入门路线（LLM / Agent / 多模态 / MLOps）</a></li></ul></li><li><strong>进入主路径（建议顺序）</strong><ul><li><a href="/my-vitepress-site/ai/llm-basics.html">LLM 入门与 Prompt 规划</a> → <a href="/my-vitepress-site/ai/agent-basics.html">Agent / 工具型 AI</a> → <a href="/my-vitepress-site/ai/mvp-server.html">MVP Server / 数据中台</a></li></ul></li><li><strong>按需选修进阶</strong><ul><li><a href="/my-vitepress-site/ai/multimodal-kg.html">多模态 &amp; 知识图谱</a> / <a href="/my-vitepress-site/ai/mlops-platform.html">部署 &amp; MLOps</a></li></ul></li></ol><hr><h2 id="📚-三个阶段的「模块化文章」版-一步步学" tabindex="-1">📚 三个阶段的「模块化文章」版（一步步学） <a class="header-anchor" href="#📚-三个阶段的「模块化文章」版-一步步学" aria-label="Permalink to “📚 三个阶段的「模块化文章」版（一步步学）”">​</a></h2><p>如果你更希望<strong>按文章顺序一步步练</strong>（每篇都有练习/验收点），从这里进入：</p><ol><li><strong>阶段一模块：LLM &amp; Prompt（循序渐进）</strong><ul><li><a href="/my-vitepress-site/ai/stage-1-llm/">模块导航：阶段一（LLM &amp; Prompt）</a></li></ul></li><li><strong>阶段二模块：Agent &amp; Tools（循序渐进）</strong><ul><li><a href="/my-vitepress-site/ai/stage-2-agent/">模块导航：阶段二（Agent &amp; Tools）</a></li></ul></li><li><strong>阶段三模块：MVP Server / 数据中台（循序渐进）</strong><ul><li><a href="/my-vitepress-site/ai/stage-3-mvp-server/">模块导航：阶段三（MVP Server）</a></li></ul></li></ol><hr><h2 id="🧩-大模型部署及使用-本地-云端" tabindex="-1">🧩 大模型部署及使用（本地/云端） <a class="header-anchor" href="#🧩-大模型部署及使用-本地-云端" aria-label="Permalink to “🧩 大模型部署及使用（本地/云端）”">​</a></h2><ul><li><a href="/my-vitepress-site/ai/model-deploy/">模块导航：大模型部署及使用</a><ul><li><a href="/my-vitepress-site/ai/model-deploy/01-local-deploy.html">本地部署</a></li><li><a href="/my-vitepress-site/ai/model-deploy/02-cloud-deploy.html">云端部署</a></li><li><a href="/my-vitepress-site/ai/model-deploy/03-model-selection.html">模型选择指南（按环境/场景）</a></li><li><a href="/my-vitepress-site/ai/model-deploy/04-runtime-compare.html">推理框架/工具对比与选型（2026）</a></li></ul></li></ul><hr><h2 id="🧪-推荐执行顺序-先快后深" tabindex="-1">🧪 推荐执行顺序（先快后深） <a class="header-anchor" href="#🧪-推荐执行顺序-先快后深" aria-label="Permalink to “🧪 推荐执行顺序（先快后深）”">​</a></h2><blockquote><p>目标不变：<strong>先做出能用的小工具，再逐步升级工程能力</strong>。</p></blockquote><ul><li><strong>第 0 步（3-7 天）</strong>：先完成 <a href="/my-vitepress-site/ai/quickstart.html">AI 快速入门（7 天）</a></li><li><strong>第 1 步（1-2 周）</strong>：走主路径 <ul><li><a href="/my-vitepress-site/ai/llm-basics.html">LLM 入门</a> → <a href="/my-vitepress-site/ai/agent-basics.html">Agent 入门</a></li></ul></li><li><strong>第 2 步（1-3 周）</strong>：加数据中台 <ul><li><a href="/my-vitepress-site/ai/mvp-server.html">MVP Server</a></li></ul></li><li><strong>第 3 步（选修）</strong>：做更聪明/更稳定 <ul><li><a href="/my-vitepress-site/ai/multimodal-kg.html">多模态 &amp; 知识图谱</a> / <a href="/my-vitepress-site/ai/mlops-platform.html">部署 &amp; MLOps</a></li></ul></li></ul><blockquote><p>总结一句：<strong>先 LLM → 再单工具 Agent → 再 MVP Server → 再 RAG/部署</strong>。</p></blockquote><hr><h2 id="🎯-模块定位-和技术库分开的原因" tabindex="-1">🎯 模块定位：和技术库分开的原因 <a class="header-anchor" href="#🎯-模块定位-和技术库分开的原因" aria-label="Permalink to “🎯 模块定位：和技术库分开的原因”">​</a></h2><ul><li><strong>技术库</strong>：更多是 Java / 数据库 / Redis / 框架 等传统知识点，偏“面试 &amp; 基础能力”。</li><li><strong>AI 模块</strong>：专门围绕 <strong>LLM / Agent / RAG / 部署 &amp; MLOps</strong>，规划「从普通开发 → 能上手 AI 工程与产品」的路线。</li></ul><p>以后和 AI 有关的新内容（如：本地大模型部署、Agent 实战、知识库问答项目等），统一放在这个模块下，方便单独规划与回顾。</p><hr><h2 id="🔗-关联模块" tabindex="-1">🔗 关联模块 <a class="header-anchor" href="#🔗-关联模块" aria-label="Permalink to “🔗 关联模块”">​</a></h2><ul><li>技术体系总览：<code>/tech-system/</code></li><li>开源项目中的 AI &amp; 大模型实践：<code>/open-source/ai-projects</code>、<code>/open-source/llm-projects</code></li></ul>',29)])])}const c=a(r,[["render",s]]);export{d as __pageData,c as default};
